-- 007_n4_words_heian
-- N4 單字匯入：平安神宮（CSV 行 322-641，共 320 字）
-- 資料源：stephenmk/yomitan-jlpt-vocab (CC-BY, Jonathan Waller / Tanos)
-- 中文翻譯：Claude（學生友善口語風格）

with new_words as (
  returning id, lemma
)
select
  (select id from shrines where slug = 'heian'),
  nw.id,
  row_number() over (order by nw.lemma)
from new_words nw;
